/// <summary>
/// Runtime oracle for the L2-event-handler-basic eval case (docs/AGENT_EVAL_LOOP.md §6.3).
///
/// The case asks the agent to add a [DataEventHandler] on ConDemoNoteHeader's
/// Inserting event that defaults Subject to '(no subject)' when left blank --
/// the OTHER extensibility mechanism alongside CoC (event handlers fire
/// out-of-band, cannot return a value or block the call the way a CoC wrapper
/// can). A golden diff can confirm the handler class + attribute exist with
/// the right signature, but not that the default is actually applied at
/// runtime -- that needs a real insert.
///
/// Run via `run_systest_class` with className = EvalL2EventHandlerDefaultSubjectTest.
/// </summary>
class EvalL2EventHandlerDefaultSubjectTest extends SysTestCase
{
}

Method.Source:
/// <summary>
/// Inserting with no Subject set triggers the handler's default.
/// </summary>
[SysTestCheckInTestAttribute]
public void testInsertingWithBlankSubjectGetsDefaulted()
{
    ConDemoNoteHeader noteHeader;
    noteHeader.NoteId = 'EVT-TEST-1';
    noteHeader.insert();

    this.assertEquals('(no subject)', noteHeader.Subject);
}

/// <summary>
/// An explicit Subject is left untouched by the handler.
/// </summary>
[SysTestCheckInTestAttribute]
public void testInsertingWithExplicitSubjectIsPreserved()
{
    ConDemoNoteHeader noteHeader;
    noteHeader.NoteId = 'EVT-TEST-2';
    noteHeader.Subject = 'Explicit subject';
    noteHeader.insert();

    this.assertEquals('Explicit subject', noteHeader.Subject);
}
